    conviction_level: 8,
    metrics: {
      r2_value: data.r2_heating_oil || 0.87,
      score: 8
    },
    constraints_satisfied: true,
    action_required: false,
    ifrs9_eligible: data.r2_heating_oil >= 0.80,
    rationale: "Neutral macro environment. Moderate geopolitical risk. Recommend hedging.",
    generated_at: new Date().toISOString()
  }
}];

const agents = $input.all();

let votesInFavor = 0;
let convictionSum = 0;
let criticalRisks = [];
let ifrs9Eligible = true;
let constraintsSatisfied = true;

for (const agent of agents) {
  const agentData = agent.json;
  if (agentData.recommendation === 'HEDGE') votesInFavor++;
  convictionSum += agentData.conviction_level || 0;
  if (agentData.risk_level === 'CRITICAL') criticalRisks.push(agentData.agent_id);
  if (agentData.ifrs9_eligible === false) ifrs9Eligible = false;
  if (agentData.constraints_satisfied === false) constraintsSatisfied = false;
}

const avgConviction = convictionSum / agents.length;

return [{
  json: {
    votes_in_favor: votesInFavor,
    votes_total: agents.length,
    conviction_avg: avgConviction,
    critical_risks: criticalRisks,
    ifrs9_eligible: ifrs9Eligible,
    constraints_satisfied: constraintsSatisfied,
    agent_outputs: agents.map(a => a.json)
  }
}];

const committee = $input.first().json;

let decision = "REJECT";
let rationale = "";

if (!committee.constraints_satisfied) {
  decision = "REJECT";
  rationale = "Hard constraints violated (HR > 80% or Collateral > 15%)";
} else if (!committee.ifrs9_eligible) {
  decision = "REJECT";
  rationale = "IFRS 9 not eligible (R² < 0.80)";
} else if (committee.critical_risks.length > 0) {
  decision = "REJECT";
  rationale = `Critical risks: ${committee.critical_risks.join(', ')}`;
} else if (committee.votes_in_favor >= 4) {
  decision = "IMPLEMENT";
  rationale = "Strong consensus (4-5/5 agents). All constraints satisfied.";
} else if (committee.votes_in_favor === 3) {
  decision = "MODIFY";
  rationale = "Moderate consensus (3/5). Reduce position size by 30%.";
} else {
  decision = "MONITOR";
  rationale = "Weak consensus. Wait for better conditions.";
}

const recommendation = {
  recommendation_type: decision === "IMPLEMENT" ? "HEDGE_NEW" : "WAIT",
  instrument: "heating_oil",
  notional_usd: decision === "MODIFY" ? 3500000 : 5000000,
  contracts: decision === "MODIFY" ? 350 : 500,
  hedge_ratio_pct: decision === "MODIFY" ? 55.0 : 75.0,
  ifrs9_eligible: committee.ifrs9_eligible,
  agent_consensus: {
    votes_in_favor: committee.votes_in_favor,
    conviction_avg: committee.conviction_avg
  },
  cro_decision: decision,
  cro_rationale: rationale,
  action_required: decision === "IMPLEMENT",
  requires_cfo_approval: true,
  generated_at: new Date().toISOString()
};

return [{ json: recommendation }];

const rec = $input.first().json;

console.log('🎯 FINAL HEDGE RECOMMENDATION:');
console.log(`Decision: ${rec.cro_decision}`);
console.log(`Rationale: ${rec.cro_rationale}`);
console.log(`Instrument: ${rec.instrument}`);
console.log(`Notional: $${rec.notional_usd.toLocaleString()}`);
console.log(`Contracts: ${rec.contracts}`);
console.log(`Hedge Ratio: ${rec.hedge_ratio_pct}%`);
console.log(`IFRS 9 Eligible: ${rec.ifrs9_eligible ? 'YES' : 'NO'}`);
console.log(`Consensus: ${rec.agent_consensus.votes_in_favor}/5 votes`);
console.log(`Generated: ${rec.generated_at}`);

return [{ 
  json: {
    ...rec,
    workflow_status: "COMPLETE",
    summary: `${rec.cro_decision}: ${rec.cro_rationale}`
  }
}];
